import{_ as t,o as s,c as i,ae as p}from"./chunks/framework.BvHJbMD4.js";const e="/assets/image-2.Ckr5KKQv.png",o="/assets/image-3.Otw2goRh.png",n="/assets/image-4.CdmXqUR6.png",r="/assets/image-5.BVRTBszf.png",l="/assets/image-6.DsY5HZOj.png",u=JSON.parse('{"title":"五、进阶指南","description":"","frontmatter":{},"headers":[],"relativePath":"advanced.md","filePath":"advanced.md"}'),h={name:"advanced.md"};function g(d,a,y,x,c,m){return s(),i("div",null,[...a[0]||(a[0]=[p('<h1 id="五、进阶指南" tabindex="-1">五、进阶指南 <a class="header-anchor" href="#五、进阶指南" aria-label="Permalink to &quot;五、进阶指南&quot;">​</a></h1><h2 id="一-xiaoya-alist相关" tabindex="-1"><strong>（一）xiaoya alist相关</strong> <a class="header-anchor" href="#一-xiaoya-alist相关" aria-label="Permalink to &quot;**（一）xiaoya alist相关**&quot;">​</a></h2><p><strong>1.webdav挂载其他网盘到xiaoya alist：</strong></p><p>详见<a href="https://t.me/xiaoyaliu00/895158" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/895158</a></p><p><strong>2.xiaoya挂载本地硬盘文件目录</strong></p><p>xiaoya配置目录新建local_dir.txt，就能在“ip:5678/NAS” 目录访问，你可以把本地的视频，音频，甚至其它文件加载到xiaoya，目前暂时仅能挂载1个本地目录</p><p><strong>3.公网安全措施：</strong></p><p>①配置域名，配合下文“公网访问限制”</p><p>②如果路由器做端口转发，配置一个30000以上的端口，比如 30283-&gt;5678</p><p>③配置xiaoya的webdav域名，也就是编辑 guestpass.txt</p><p>④定期重启光猫，变更ip详见</p><p><strong>4.外网安全检查：</strong></p><p>详见<a href="https://t.me/xiaoyaliu00/918606" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/918606</a></p><p><strong>5.公网访问限制：</strong></p><p>详见<a href="https://t.me/xiaoyaliu00/974894" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/974894</a></p><p><strong>6.签名机制：</strong></p><p>详见<a href="https://t.me/xiaoyaliu00/1091310" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/1091310</a></p><p><strong>7.查看115网盘目录ID的方法：</strong></p><p><img src="'+e+'" alt="image.png"></p><p><img src="'+o+'" alt="image.png"></p><p><strong>8.xiaoya alist中添加“我的115”：</strong></p><p>xiaoya配置目录下，配置115_list.txt（具体内容见下），重启xiaoya生效</p><p>①如挂根目录，则群文件找一个，txt内容是 “115 0”</p><p>②如挂具体内幕，准确的格式是：</p><p>挂载名称 [空格] 目录id [空格] 目录密码 [回车]</p><p>没有密码就不用填密码，格式里面注明的空格和回车都要补上，例如：</p><p>挂载名称 [空格] 目录id [空格] [回车]</p><p><strong>9.xiaoya alist中添加“我的阿里云盘”：</strong></p><p>xiaoya配置目录下，配置show_my_ali.txt（直接群文件找现成的），重启xiaoya生效</p><p><strong>10.xiaoya alist中添加“我的阿里分享”：</strong></p><p>xiaoya配置目录下，配置alishare_list.txt（群文件有模板），准确的格式是：</p><p>挂载名称 [空格] 阿里分享ID [空格] 文件folder id [空格] 目录密码 [回车]</p><p>没有密码就不用填密码，格式里面注明的空格和回车都要补上，挂载名不能有空格</p><p><img src="'+n+'" alt="image.png"></p><p><strong>11.xiaoya alist中添加“我的115分享”：</strong></p><p>xiaoya配置目录下，配置115share_list.txt（群文件有模板），准确的格式是：</p><p>挂载名称 [空格] 115分享ID [空格] 分享目录id提取码 [空格] 目录密码 [回车]</p><p>没有密码就不用填密码，格式里面注明的空格和回车都要补上，挂载名不能有空格</p><p><strong>12.设置xiaoya.host映射</strong></p><p>①软路由上设置：也就是全屋通用，比如默认网关和dns都在n1上，然后在n1的/etc/hosts 里配置 xiaoya.host （格式见图）</p><p><img src="'+r+'" alt="image.png"></p><p>n1的IP是 192.168.2.8</p><p>xiaoya 所在的硬件 IP是 192.168.2.81</p><p>每个人的网络环境不一样，配置方法也不一样，如果你的软路由无法修改 /etc/hosts，那么可以用其它dns软件比如smartdns来实现类似的结果</p><p>②播放设备上设置：如果实在不会配置路由器上的解析，那么退而求其次，配置播放设备上的解析（只对单台设备起作用，比较麻烦，手机要配置，PC要配置，电视盒子要配置）</p><p>安卓手机：<a href="https://github.com/x-falcon/Virtual-Hosts" target="_blank" rel="noreferrer">https://github.com/x-falcon/Virtual-Hosts</a></p><p>苹果 mac，ios应该也有类似的工具</p><p>③windows设置：编辑C:\\Windows\\System32\\drivers\\etc\\hosts,添加xiaoya.host 及对应ip</p><p><strong>13.设置xiaoya alist定时重启：</strong></p><p>装好xiaoyakeeper（xiaoyahelper）,xiaoya配置目录下，配置myruntime.txt（模板群文件有），myruntime.txt中定义的时间点会做三件事：一是重启小雅；二是如果小雅有更新就更新小雅（如不想更新，则在mycmd.txt用“#”注释update_xiaoya那一行）；三是做一次清理。如果没有myruntime.txt这个文件，则默认xiaoyakeeper的启动/重启时干这三件事</p><p><strong>14.alist套娃xiaoya alist：</strong></p><p>通过v3驱动方式套娃，把令牌填到 Authorization（令牌见xiaoya配置目录中alist_auth_token.txt），Server填部署xiaoya的设备内网ip，不要填账号和密码</p><p>请注意，套webdav驱动无302，套openlist驱动可以302。套娃会丧失搜索功能和阿里转码播放功能</p><p><strong>15.xiaoya alist套娃alist：</strong></p><p>xiaoya配置目录下，配置alist_list.txt（群文件有模板），可以挂载挂载一个或多个 Alist 套娃，txt内容最下面需要留一个空行，重启xiaoya生效</p><p><strong>16.建立自己的索引：</strong></p><p>①把alist挂到本地硬盘，可以用rclone和davfs2 来实现，小雅是用轻量级的dafs2，配置非常简单，安装davfs2后，执行以下命令</p><div class="language-jsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mkdir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mnt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">xiaoya</span></span></code></pre></div><div class="language-jsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mount.davfs </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//xxx:5678/dav  /mnt/xiaoya</span></span></code></pre></div><p>然后输入用户名、密码，然后执行命令</p><div class="language-jsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mnt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">xiaoya</span></span></code></pre></div><div class="language-jsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">find .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">元数据</span></span></code></pre></div><p>就是拉了个“/元数据”目录的清单，其他目录以此类推</p><p>②xiaoya配置目录下，新建myindex.txt，把上面生成的索引黏贴进去，最后留一个空行，保存，重启xiaoya生效</p><h2 id="二-xiaoya-emby相关" tabindex="-1"><strong>（二）xiaoya emby相关</strong> <a class="header-anchor" href="#二-xiaoya-emby相关" aria-label="Permalink to &quot;**（二）xiaoya emby相关**&quot;">​</a></h2><p><strong>1.ConverArt插件（emby 115、iso媒体封面标识）：</strong></p><p>详见 <a href="https://t.me/xiaoyaliu00/1220110" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/1220110</a></p><p><strong>2.将xiaoya alist中的资源添加到emby：</strong></p><p>详见 <a href="https://www.notion.so/d353c9ceb15444d7b8e21ce6097ed739?pvs=21" target="_blank" rel="noreferrer">https://xiaoyaliu.notion.site/d353c9ceb15444d7b8e21ce6097ed739?v=145044ac8252470a9feef094ff1db520</a></p><p>因115风控收紧，自己拉strm的，把一个大目录拆分成一堆小的子目录，分批执行，中间加插停顿，具体参考<a href="https://t.me/xiaoyaliu00/1361900" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/1361900</a></p><p><strong>3.安装神医助手（首字母搜索）</strong></p><p>①<a href="https://t.me/xiaoyaliu00/1259686" target="_blank" rel="noreferrer">https://t.me/xiaoyaliu00/1259686</a>下载后，放入“本地媒体库目录/config/plugins”文件夹中</p><p>②重启emby</p><p>③如提示“魔改失败”，<a href="https://github.com/sjtuross/StrmAssistant.Releases/blob/main/plugins/MovieDb_10.8.6.0.zip" target="_blank" rel="noreferrer">https://github.com/sjtuross/StrmAssistant.Releases/blob/main/plugins/MovieDb_10.8.6.0.zip</a>下载解压 MovieDb10.8.6替换同名dll，重启emby</p><p>④“中文搜索增强-搜索范围”取消“合集”勾选</p><p><img src="'+l+'" alt="image.png"></p><p>注意：不要动任何神医的设置！除非你知道你在做什么！</p><p><strong>4.设置每日定时扫库：</strong></p><p>浏览器打开ip:2345，右上角“设置”，左边栏“计划任务”，点击“Scan media library”，点击“添加触发器”，建议扫库时间设置在后半夜</p>',79)])])}const b=t(h,[["render",g]]);export{u as __pageData,b as default};
